@rendermode InteractiveServer

@using RecipeCommunity.Services
@inject RecipeService RecipeService

<div class="star-rating d-inline-flex align-items-center gap-2">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= (_userRating ?? 0) ? "rated" : (star <= HoverStar ? "hover" : ""))"
              role="button"
              @onclick="() => Rate(star)"
              @onmouseover="() => HoverStar = star"
              @onmouseout="() => HoverStar = 0">
            ★
        </span>
    }
    <span class="text-muted small ms-2">
        @if (_userRating.HasValue)
        {
            <text>You rated @_userRating ★</text>
        }
        else
        {
            <text>Click to rate</text>
        }
    </span>
</div>

<style>
    .star-rating .star {
        font-size: 1.8rem;
        color: #ccc;
        cursor: pointer;
        transition: color 0.15s;
    }
    .star-rating .star.rated {
        color: #ffc107;
    }
    .star-rating .star.hover {
        color: #ffdb4d;
    }
</style>

@code {
    [Parameter] public int RecipeId { get; set; }

    private int? _userRating;
    private int HoverStar { get; set; }

    private void Rate(int stars)
    {
        _userRating = stars;
        RecipeService.AddRating(RecipeId, stars);
    }
}

