@rendermode InteractiveServer

@using RecipeCommunity.Models
@using RecipeCommunity.Services
@inject RecipeService RecipeService
@inject NavigationManager Navigation

<div class="card shadow-sm">
    <div class="card-body">
        <h3 class="card-title">Share Your Recipe</h3>

        @if (_submitted)
        {
            <div class="alert alert-success">
                <strong>Thanks!</strong> Your recipe "<em>@_submission.Title</em>" has been submitted.
                <a href="/category/@_submission.Category">View in @_submission.Category →</a>
            </div>
        }
        else
        {
            <EditForm Model="_submission" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
                <div class="mb-3">
                    <label class="form-label fw-bold">Recipe Title</label>
                    <InputText class="form-control" @bind-Value="_submission.Title" placeholder="e.g. Grandma's Apple Pie" />
                </div>

                <div class="mb-3">
                    <label class="form-label fw-bold">Category</label>
                    <InputSelect class="form-select" @bind-Value="_submission.Category">
                        <option value="">— Select a category —</option>
                        @foreach (var cat in _categories)
                        {
                            <option value="@cat">@cat</option>
                        }
                        <option value="Other">Other</option>
                    </InputSelect>
                </div>

                <div class="mb-3">
                    <label class="form-label fw-bold">Ingredients</label>
                    <InputTextArea class="form-control" rows="5" @bind-Value="_submission.Ingredients"
                                   placeholder="One ingredient per line&#10;e.g.&#10;2 cups flour&#10;1 cup sugar&#10;3 eggs" />
                    <div class="form-text">Enter one ingredient per line.</div>
                </div>

                <div class="mb-3">
                    <label class="form-label fw-bold">Steps</label>
                    <InputTextArea class="form-control" rows="5" @bind-Value="_submission.Steps"
                                   placeholder="One step per line&#10;e.g.&#10;Preheat oven to 350°F&#10;Mix dry ingredients&#10;Add wet ingredients" />
                    <div class="form-text">Enter one step per line.</div>
                </div>

                <button type="submit" class="btn btn-primary"
                        disabled="@(string.IsNullOrWhiteSpace(_submission.Title) || string.IsNullOrWhiteSpace(_submission.Category))">
                    Submit Recipe
                </button>
            </EditForm>
        }
    </div>
</div>

@code {
    private RecipeSubmission _submission = new();
    private List<string> _categories = [];
    private bool _submitted;

    protected override void OnInitialized()
    {
        _categories = RecipeService.GetCategories();
    }

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(_submission.Title) ||
            string.IsNullOrWhiteSpace(_submission.Category) ||
            string.IsNullOrWhiteSpace(_submission.Ingredients) ||
            string.IsNullOrWhiteSpace(_submission.Steps))
            return;

        RecipeService.AddRecipe(_submission);
        _submitted = true;
    }
}

