@page "/"

@using RecipeCommunity.Services
@inject RecipeService RecipeService

<PageTitle>Recipe Community</PageTitle>

<div class="text-center mb-5">
    <h1 class="display-4 fw-bold">🍳 Recipe Community</h1>
    <p class="lead text-muted">Discover, share, and rate delicious recipes from around the world.</p>
</div>

<div class="row g-4">
    @foreach (var category in RecipeService.GetCategories())
    {
        var recipes = RecipeService.GetByCategory(category);
        var emoji = category switch
        {
            "Italian" => "🍝",
            "Mexican" => "🌮",
            "Indian" => "🍛",
            "Asian" => "🥡",
            "Desserts" => "🍫",
            _ => "🍽️"
        };

        <div class="col-md-4 col-sm-6">
            <a href="/category/@category" class="text-decoration-none">
                <div class="card h-100 shadow-sm border-0 category-card">
                    <div class="card-body text-center py-4">
                        <div class="display-3 mb-2">@emoji</div>
                        <h3 class="card-title">@category</h3>
                        <p class="text-muted">@recipes.Count recipe@(recipes.Count != 1 ? "s" : "")</p>
                    </div>
                </div>
            </a>
        </div>
    }
</div>

<div class="text-center mt-5">
    <a href="/submit" class="btn btn-primary btn-lg">📝 Submit a Recipe</a>
</div>

<style>
    .category-card {
        transition: transform 0.2s, box-shadow 0.2s;
    }
    .category-card:hover {
        transform: translateY(-4px);
        box-shadow: 0 .5rem 1rem rgba(0,0,0,.15) !important;
    }
</style>

