else
{
    <div class="row g-4">
        @foreach (var recipe in _recipes)
        {
            <div class="col-md-6">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h4 class="card-title">
                            <a href="/recipe/@recipe.Id" class="text-decoration-none">@recipe.Title</a>
                        </h4>
                        <p class="card-text text-muted">@recipe.Description</p>
                        <div class="d-flex justify-content-between align-items-center">
                            <span class="text-warning">
                                @for (int i = 1; i <= 5; i++)
                                {
                                    <text>@(i <= (int)Math.Round(recipe.AverageRating) ? "★" : "☆")</text>
                                }
                            </span>
                            <small class="text-muted">@recipe.TotalRatings ratings</small>
                        </div>
                    </div>
                    <div class="card-footer bg-transparent">
                        <a href="/recipe/@recipe.Id" class="btn btn-outline-primary btn-sm">View Recipe →</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;

