@using RecipeCommunity.Models
@using RecipeCommunity.Services
@using RecipeCommunity.Components.Shared
@inject RecipeService RecipeService

<PageTitle>@(_recipe?.Title ?? "Recipe") — Recipe Community</PageTitle>

@if (_recipe is null)
{
    <div class="alert alert-warning">Recipe not found.</div>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="/category/@_recipe.Category">@_recipe.Category</a></li>
            <li class="breadcrumb-item active">@_recipe.Title</li>
        </ol>
    </nav>

    <div class="row">
        <div class="col-lg-8">
            <h1 class="mb-2">@_recipe.Title</h1>
            <p class="lead text-muted mb-3">@_recipe.Description</p>

            <div class="mb-4 p-3 bg-light rounded">
                <strong>Average:</strong>
                <span class="text-warning ms-1">
                    @for (int i = 1; i <= 5; i++)
                    {
                        <text>@(i <= (int)Math.Round(_recipe.AverageRating) ? "★" : "☆")</text>
                    }
                </span>
                <span class="text-muted ms-2">(@_recipe.AverageRating.ToString("0.0") from @_recipe.TotalRatings ratings)</span>
            </div>

            <div class="mb-4">
                <strong>Rate this recipe:</strong>
                <div class="mt-1">
                    <StarRating RecipeId="_recipe.Id" />
                </div>
            </div>

            <h3>📋 Ingredients</h3>
            <ul class="list-group list-group-flush mb-4">
                @foreach (var ingredient in _recipe.Ingredients)
                {
                    <li class="list-group-item">@ingredient</li>
                }
            </ul>

            <h3>👨‍🍳 Steps</h3>
            <ol class="list-group list-group-numbered list-group-flush mb-4">
                @foreach (var step in _recipe.Steps)
                {
                    <li class="list-group-item">@step</li>
                }
            </ol>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Recipe? _recipe;

    protected override void OnInitialized()
    {
        _recipe = RecipeService.GetById(Id);
    }
}

